import { allEncounters, encounterTable } from '../data/encounter.data.js';
import { isRollsWithEncounters } from '../models/encounter.model.js';
import { getTerrainKeys } from '../models/terrain.model.js';
export const getTerrainsByEncounterId = id => {
  if (id === 0 || id === 1) {
    return [...getTerrainKeys()];
  }

  return Object.entries(encounterTable).reduce((acc, [terrain, encounters]) => {
    const hasEncounter = Object.values(encounters).some(e => e === id);

    if (hasEncounter) {
      acc.push(terrain);
    }

    return acc;
  }, []);
};

const createEncounterViewModel = (id, lang) => ({
  id,
  ...allEncounters[lang][id],
  terrains: getTerrainsByEncounterId(id)
});

export const getEncounterById = (id, lang) => {
  return createEncounterViewModel(id, lang);
};
export const getRandomEncounter = (roll, terrain, lang) => {
  if (!isRollsWithEncounters(roll)) {
    return createEncounterViewModel(0, lang);
  }

  const randomEncounterId = encounterTable[terrain][roll];
  const encounterExists = Object.keys(allEncounters[lang]).includes(randomEncounterId.toString());

  if (!encounterExists) {
    return createEncounterViewModel(0, lang);
  }

  return createEncounterViewModel(randomEncounterId, lang);
};